INSERT INTO post_vote_option (post_id, label, ordinal, semantic_key)
SELECT id, 'Agree', 0, 'AGREE' FROM post WHERE id BETWEEN 1000 AND 1009;
INSERT INTO post_vote_option (post_id, label, ordinal, semantic_key)
SELECT id, 'Disagree', 1, 'DISAGREE' FROM post WHERE id BETWEEN 1000 AND 1009;
